# Define a tool schema
tools = [
    {
        "name": "get_weather",
        "description": "Get the current weather for a given city. Use this when the user asks about weather conditions.",
        "input_schema": {
            "type": "object",
            "properties": {
                "city": {
                    "type": "string",
                    "description": "The city name, e.g. 'San Francisco'"
                },
                "unit": {
                    "type": "string",
                    "enum": ["celsius", "fahrenheit"],
                    "description": "Temperature unit"
                }
            },
            "required": ["city"]
        }
    }
]

import anthropic

client = anthropic.Anthropic()

response = client.messages.create(
    model="claude-sonnet-4-20250514",
    max_tokens=1024,
    tools=tools,
    messages=[
        {"role": "user", "content": "What is the weather in Tokyo?"}
    ]
)

# Check if Claude wants to use a tool
print(f"Stop reason: {response.stop_reason}")  # "tool_use"

for block in response.content:
    if block.type == "tool_use":
        print(f"Tool: {block.name}")       # "get_weather"
        print(f"Input: {block.input}")     # {"city": "Tokyo"}
        print(f"Tool ID: {block.id}")      # "toolu_..."

def execute_tool(name: str, inputs: dict) -> str:
    """Execute a tool and return the result as a string."""
    if name == "get_weather":
        # In production, call a real weather API
        city = inputs["city"]
        return f"The weather in {city} is 22C and sunny."
    return "Unknown tool."

# Process tool calls from the response
tool_results = []
for block in response.content:
    if block.type == "tool_use":
        result = execute_tool(block.name, block.input)
        tool_results.append({
            "type": "tool_result",
            "tool_use_id": block.id,
            "content": result
        })

# Send tool results back to Claude
final_response = client.messages.create(
    model="claude-sonnet-4-20250514",
    max_tokens=1024,
    tools=tools,
    messages=[
        {"role": "user", "content": "What is the weather in Tokyo?"},
        {"role": "assistant", "content": response.content},
        {"role": "user", "content": tool_results}
    ]
)

print(final_response.content[0].text)

import anthropic

client = anthropic.Anthropic()

tools = [
    {
        "name": "get_weather",
        "description": "Get current weather for a city.",
        "input_schema": {
            "type": "object",
            "properties": {
                "city": {"type": "string", "description": "City name"}
            },
            "required": ["city"]
        }
    },
    {
        "name": "search_restaurants",
        "description": "Search for restaurants in a city, optionally filtered by cuisine.",
        "input_schema": {
            "type": "object",
            "properties": {
                "city": {"type": "string", "description": "City name"},
                "cuisine": {"type": "string", "description": "Cuisine type, e.g. 'Italian'"}
            },
            "required": ["city"]
        }
    }
]

def run_tool(name: str, inputs: dict) -> str:
    if name == "get_weather":
        return f"Weather in {inputs['city']}: 18C, cloudy."
    elif name == "search_restaurants":
        cuisine = inputs.get('cuisine', 'any')
        return f"Top restaurants in {inputs['city']} ({cuisine}): Sakura, Mondo, Chez Paul."
    return "Unknown tool."

def chat_with_tools(user_message: str) -> str:
    messages = [{"role": "user", "content": user_message}]

    while True:
        response = client.messages.create(
            model="claude-sonnet-4-20250514",
            max_tokens=1024,
            tools=tools,
            messages=messages
        )

        # If Claude is done (no more tool calls), return the text
        if response.stop_reason == "end_turn":
            return response.content[0].text

        # Process tool calls
        messages.append({"role": "assistant", "content": response.content})
        tool_results = []
        for block in response.content:
            if block.type == "tool_use":
                result = run_tool(block.name, block.input)
                tool_results.append({
                    "type": "tool_result",
                    "tool_use_id": block.id,
                    "content": result
                })
        messages.append({"role": "user", "content": tool_results})

print(chat_with_tools("What is the weather in Paris and find me Italian restaurants there?"))
